code = """import json

available_vars = list(locals().keys())
print('AVAILABLE VARIABLES:' + str(available_vars))

business_data_var = None
for var in available_vars:
    if 'query_db:5' in var:
        business_data_var = var
        break

if not business_data_var:
    print('No business data found in variables')
    # Try direct access to business data
    for var in available_vars:
        if isinstance(locals()[var], list) and len(locals()[var]) > 0:
            data = locals()[var]
            if isinstance(data[0], dict) and 'business_id' in data[0]:
                business_data = data
                print('Found business data by content matching')
                break
    else:
        business_data = []
else:
    business_data = locals()[business_data_var]

print('Data type: ' + str(type(business_data)))
print('Data length: ' + str(len(business_data)))

if len(business_data) > 0:
    print('Sample business: ' + str(business_data[0]))

total_wifi = 0
wifi_values = []
state_counts = {}

print('Analyzing ' + str(len(business_data)) + ' businesses...')

for i, business in enumerate(business_data):
    attrs = business.get('attributes')
    has_wifi = False
    
    if isinstance(attrs, dict):
        for key, value in attrs.items():
            if 'wifi' in str(key).lower():
                wifi_val = str(value)
                has_wifi = True
                wifi_values.append(wifi_val)
                break
                
    state = None
    desc = business.get('description', '')
    
    if ', ' in desc:
        parts = desc.rsplit(', ', 1)
        if len(parts) == 2:
            potential_state = parts[1].strip()
            state_words = potential_state.split()
            if state_words:
                if len(state_words[0]) == 2 and state_words[0].isalpha():
                    state = state_words[0]
    
    if has_wifi and state:
        total_wifi += 1
        state_counts[state] = state_counts.get(state, 0) + 1
    
    if (i + 1) % 1000 == 0:
        print('Processed ' + str(i + 1) + ' businesses...')

print('=== RESULTS ===')
print('Total with WiFi: ' + str(total_wifi))

sorted_states = sorted(state_counts.items(), key=lambda x: x[1], reverse=True)[:10]
print('Top 10 states:')
for state, count in sorted_states:
    print('  ' + state + ': ' + str(count))

top_state = None
if state_counts:
    top_state = max(state_counts.items(), key=lambda x: x[1])

# Get related business IDs
top_businesses = []
if top_state:
    for business in business_data:
        attrs = business.get('attributes')
        has_wifi = False
        if isinstance(attrs, dict):
            for key, value in attrs.items():
                if 'wifi' in str(key).lower():
                    if 'no' not in str(value).lower():
                        has_wifi = True
        
        if has_wifi:
            desc = business.get('description', '')
            if ', ' in desc:
                parts = desc.rsplit(', ', 1)
                if len(parts) == 2:
                    potential_state = parts[1].strip()
                    state_words = potential_state.split()
                    if state_words and len(state_words[0]) == 2 and state_words[0].isalpha():
                        biz_state = state_words[0]
                        if biz_state == top_state[0]:
                            top_businesses.append(business['business_id'])

result = {
    'total_businesses': len(business_data),
    'wifi_count': total_wifi,
    'top_state': top_state[0] if top_state else None,
    'top_state_count': top_state[1] if top_state else 0,
    'top_10_states': dict(sorted_states),
    'sample_ids': top_businesses[:10]
}

print('__RESULT__:')
print(json.dumps(result))"""

